class Spreadsheet:
    def __init__(self):
        self.cells = {}

    def set_cell(self, cell: str, value: str):
        self.cells[cell] = value

    def get_cell(self, cell: str) -> int:
        if cell not in self.cells:
            return 0
        value = self.cells[cell]
        if value.startswith('='):
            formula = value[1:].split()
            result = self.evaluate_formula(formula)
            return result
        else:
            return int(value)

    def evaluate_formula(self, formula: list) -> int:
        stack = []
        operators = {'+': lambda a, b: a + b, '-': lambda a, b: a - b, '*': lambda a, b: a * b, '/': lambda a, b: a / b}
        for token in formula:
            if token in operators:
                b = stack.pop()
                a = stack.pop()
                stack.append(operators[token](a, b))
            else:
                stack.append(self.get_cell(token))
        return int(stack.pop())

