            formula = value[1:].split()
            result = self.evaluate_formula(formula)
            return result
        elif isinstance(value, int):
            return value
        else:
            return 0

    def evaluate_formula(self, formula: List[str]) -> int:
        stack = []
        for token in formula:
            if token in ['+', '-', '*', '/']:
                b = stack.pop()
                a = stack.pop()
                if token == '+':
                    stack.append(a + b)
                elif token == '-':
                    stack.append(a - b)
                elif token == '*':
                    stack.append(a * b)
                elif token == '/':
                    stack.append(a / b)
            else:
                value = self.get_cell(token)
                stack.append(value)
        return int(stack[-1])

